<?php
namespace App\Http\Controllers\Api;
use App\Models\{Material,Project};use Illuminate\Http\Request;use App\Http\Controllers\Controller;
class MaterialController extends Controller{public function index(Project $project){$this->authorize('view',$project);return $project->materials()->with('unit')->get();} public function store(Request $r,Project $project){$this->authorize('update',$project);return $project->materials()->create($r->validate(['unit_id'=>'required|exists:units,id','name'=>'required|string','sku'=>'nullable|string','description'=>'nullable|string','is_active'=>'boolean']));} public function show(Material $material){$this->authorize('view',$material);return $material->load('unit');} public function update(Request $r,Material $material){$this->authorize('update',$material);$material->update($r->only(['unit_id','name','sku','description','is_active']));return $material;} public function destroy(Material $material){$this->authorize('delete',$material);$material->delete();return response()->noContent();}}
